import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const c=JSON.parse('{"title":"資源ステージ","description":"","frontmatter":{},"headers":[],"relativePath":"ja/stages/resource.md","filePath":"ja/stages/resource.md","lastUpdated":1775394001000}'),i={name:"ja/stages/resource.md"};function s(n,t,r,o,h,x){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="資源ステージ" tabindex="-1">資源ステージ <a class="header-anchor" href="#資源ステージ" aria-label="Permalink to &quot;資源ステージ&quot;">​</a></h1><p>資源ステージは育成素材を効率的に収集するための常設ステージです。</p><h2 id="融蝕之墟-dissolution-ruins" tabindex="-1">融蝕之墟（Dissolution Ruins） <a class="header-anchor" href="#融蝕之墟-dissolution-ruins" aria-label="Permalink to &quot;融蝕之墟（Dissolution Ruins）&quot;">​</a></h2><p>主要な素材獲得ステージ。墨諾芬（スタミナ）を消費して挑戦します。調査行動1-2通関で解放。</p><h3 id="ドロップ素材" tabindex="-1">ドロップ素材 <a class="header-anchor" href="#ドロップ素材" aria-label="Permalink to &quot;ドロップ素材&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">素材カテゴリ</th><th style="text-align:left;">ドロップ内容</th></tr></thead><tbody><tr><td style="text-align:left;">昇格素材</td><td style="text-align:left;">初階/中階/高階昇格匣子</td></tr><tr><td style="text-align:left;">スキル素材</td><td style="text-align:left;">初階/中階/高階技能補給</td></tr><tr><td style="text-align:left;">界域素材</td><td style="text-align:left;">混沌残渣、深渕残渣、血腥残渣、宇宙残渣</td></tr><tr><td style="text-align:left;">教化素材</td><td style="text-align:left;">蒼白筆記、蒼白卷宗、蒼白典籍</td></tr><tr><td style="text-align:left;">通貨</td><td style="text-align:left;">蔷薇金券</td></tr><tr><td style="text-align:left;">経験素材</td><td style="text-align:left;">霊知制剤 I/II/III</td></tr><tr><td style="text-align:left;">突破素材</td><td style="text-align:left;">各界域専用突破素材</td></tr></tbody></table><h3 id="界域別融蝕之墟" tabindex="-1">界域別融蝕之墟 <a class="header-anchor" href="#界域別融蝕之墟" aria-label="Permalink to &quot;界域別融蝕之墟&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">ステージ</th><th style="text-align:left;">ドロップする界域素材</th><th style="text-align:left;">関連覚醒体</th></tr></thead><tbody><tr><td style="text-align:left;">混沌融蝕之墟</td><td style="text-align:left;">混沌残渣</td><td style="text-align:left;">混沌界域の覚醒体全般</td></tr><tr><td style="text-align:left;">深海融蝕之墟</td><td style="text-align:left;">深渕残渣</td><td style="text-align:left;">深海界域の覚醒体全般</td></tr><tr><td style="text-align:left;">血肉融蝕之墟</td><td style="text-align:left;">血腥残渣</td><td style="text-align:left;">血肉界域の覚醒体全般</td></tr><tr><td style="text-align:left;">超維融蝕之墟</td><td style="text-align:left;">宇宙残渣</td><td style="text-align:left;">超維界域の覚醒体全般</td></tr></tbody></table><h2 id="禁忌篆録-forbidden-inscriptions" tabindex="-1">禁忌篆録（Forbidden Inscriptions） <a class="header-anchor" href="#禁忌篆録-forbidden-inscriptions" aria-label="Permalink to &quot;禁忌篆録（Forbidden Inscriptions）&quot;">​</a></h2><p>通関後に繰り返し挑戦可能な素材ステージ。毎日リセット。</p><h2 id="超験存在-transcendent-existence" tabindex="-1">超験存在（Transcendent Existence） <a class="header-anchor" href="#超験存在-transcendent-existence" aria-label="Permalink to &quot;超験存在（Transcendent Existence）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">詳細</th></tr></thead><tbody><tr><td style="text-align:left;">タイプ</td><td style="text-align:left;">週ボス</td></tr><tr><td style="text-align:left;">リセット</td><td style="text-align:left;">毎週月曜日15:00</td></tr><tr><td style="text-align:left;">報酬</td><td style="text-align:left;">大量の育成素材</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>超験存在は報酬が豊富です。毎週必ずクリアしましょう。</p></div><h2 id="素材収集の効率的なルート" tabindex="-1">素材収集の効率的なルート <a class="header-anchor" href="#素材収集の効率的なルート" aria-label="Permalink to &quot;素材収集の効率的なルート&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">優先度</th><th style="text-align:left;">コンテンツ</th><th style="text-align:left;">理由</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:left;">超験存在（週ボス）</td><td style="text-align:left;">報酬が非常に豊富。毎週必ずクリア</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:left;">融蝕之墟</td><td style="text-align:left;">メイン素材源。必要な界域素材に合わせて周回</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:left;">外勤代理（派遣）</td><td style="text-align:left;">毎日精算で蔷薇金券・融蝕之珠・各種素材を獲得</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:left;">課程</td><td style="text-align:left;">擬態凝晶・千面印章などコア素材を獲得</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>土日は全素材が入手可能です。平日に足りない素材を土日にまとめて周回しましょう。素材は錬金システムで低級3個=高級1個に合成できます。</p></div><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">ステージ一覧</a></li><li><a href="./../items/materials.html">素材一覧</a></li><li><a href="./../guides/dailies.html">デイリー攻略</a></li></ul>',18)])])}const y=e(i,[["render",s]]);export{c as __pageData,y as default};
